package ua.university.sms.model.entity;
import jakarta.persistence.*;import java.util.*;
@Entity @Table(name="courses") public class Course{@Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id;@Column(nullable=false,length=200) private String title;@Column(nullable=false) private int credits;@Column(nullable=false,length=50) private String semester;@ManyToOne(optional=false) @JoinColumn(name="teacher_id") private Teacher teacher;@OneToMany(mappedBy="course",cascade=CascadeType.REMOVE) private List<Enrollment> enrollments=new ArrayList<>(); public Long getId(){return id;}public void setId(Long id){this.id=id;}public String getTitle(){return title;}public void setTitle(String title){this.title=title;}public int getCredits(){return credits;}public void setCredits(int credits){this.credits=credits;}public String getSemester(){return semester;}public void setSemester(String semester){this.semester=semester;}public Teacher getTeacher(){return teacher;}public void setTeacher(Teacher teacher){this.teacher=teacher;}public List<Enrollment> getEnrollments(){return enrollments;}}
